[DataEventHandler(tableStr(AslXyzNoteHeader), DataEventType::Inserting)]
public static void onInserting(Common _sender, DataEventArgs _e)
{
    AslXyzNoteHeader noteHeader = _sender as AslXyzNoteHeader;

    if (!noteHeader.Subject)
    {
        noteHeader.Subject = '(no subject)';
    }
}
